    }

    public static Color[] GetValues()
    {
        return Enum.GetValues(typeof(Color));
    }

    public static bool IsValid(string name)
    {
        return Enum.IsDefined(typeof(Color), name);
    }

    public static string GetDescription(Color color)
    {
